-- #############################################################################
-- 03_tickets_extended_columns.sql
-- #############################################################################
BEGIN;

ALTER TABLE tickets
    ADD COLUMN IF NOT EXISTS customer_name           VARCHAR(200),
    ADD COLUMN IF NOT EXISTS customer_phone          VARCHAR(30),
    ADD COLUMN IF NOT EXISTS device_display_name     VARCHAR(200),
    ADD COLUMN IF NOT EXISTS device_image_url        VARCHAR(1000),
    ADD COLUMN IF NOT EXISTS repair_services_summary VARCHAR(500),
    ADD COLUMN IF NOT EXISTS price_items_json        TEXT,
    ADD COLUMN IF NOT EXISTS missing_parts_json      TEXT,
    ADD COLUMN IF NOT EXISTS device_photos_json      TEXT,
    ADD COLUMN IF NOT EXISTS device_security_type    VARCHAR(20),
    ADD COLUMN IF NOT EXISTS device_security_value   VARCHAR(255),
    ADD COLUMN IF NOT EXISTS customer_approval       BOOLEAN,
    ADD COLUMN IF NOT EXISTS estimated_ready_at      TIMESTAMPTZ,
    ADD COLUMN IF NOT EXISTS estimated_delivery_at   TIMESTAMPTZ;

CREATE INDEX IF NOT EXISTS idx_tickets_customer_phone     ON tickets(shop_id, customer_phone);
CREATE INDEX IF NOT EXISTS idx_tickets_device_display     ON tickets(shop_id, device_display_name);

COMMIT;


-- #############################################################################
-- 04_auth_otp.sql
-- #############################################################################
BEGIN;

ALTER TABLE users
    ADD COLUMN IF NOT EXISTS otp_code VARCHAR(16);

ALTER TABLE customer_users
    ADD COLUMN IF NOT EXISTS otp_code VARCHAR(16);

CREATE INDEX IF NOT EXISTS idx_users_otp_lookup          ON users(email, otp_code);
CREATE INDEX IF NOT EXISTS idx_customer_users_otp_lookup ON customer_users(mobile, otp_code);

COMMIT;


-- #############################################################################
-- 05_shop_owner_extended.sql
-- #############################################################################
BEGIN;

ALTER TABLE users
    ADD COLUMN IF NOT EXISTS phone            VARCHAR(50),
    ADD COLUMN IF NOT EXISTS avatar_url       VARCHAR(1000),
    ADD COLUMN IF NOT EXISTS id_proof_url     VARCHAR(1000),
    ADD COLUMN IF NOT EXISTS personal_address TEXT;

ALTER TABLE shops
    ADD COLUMN IF NOT EXISTS owner_user_id          UUID REFERENCES users(id) ON DELETE SET NULL,
    ADD COLUMN IF NOT EXISTS mobile                 VARCHAR(50),
    ADD COLUMN IF NOT EXISTS district               VARCHAR(120),
    ADD COLUMN IF NOT EXISTS city                   VARCHAR(120),
    ADD COLUMN IF NOT EXISTS state                  VARCHAR(120),
    ADD COLUMN IF NOT EXISTS pincode                VARCHAR(20),
    ADD COLUMN IF NOT EXISTS latitude               NUMERIC(10, 7),
    ADD COLUMN IF NOT EXISTS longitude              NUMERIC(10, 7),
    ADD COLUMN IF NOT EXISTS front_image_url        VARCHAR(1000),
    ADD COLUMN IF NOT EXISTS gst_certificate_url    VARCHAR(1000),
    ADD COLUMN IF NOT EXISTS udyam_certificate_url  VARCHAR(1000);

CREATE INDEX IF NOT EXISTS idx_shops_owner_user_id ON shops(owner_user_id);
CREATE INDEX IF NOT EXISTS idx_shops_pincode       ON shops(pincode);

COMMIT;


-- #############################################################################
-- 06_email_verify_and_shop_meta.sql
-- #############################################################################
BEGIN;

ALTER TABLE users
    ADD COLUMN IF NOT EXISTS email_verified BOOLEAN NOT NULL DEFAULT FALSE;

ALTER TABLE shops
    ADD COLUMN IF NOT EXISTS shop_type     VARCHAR(80),
    ADD COLUMN IF NOT EXISTS business_type VARCHAR(80),
    ADD COLUMN IF NOT EXISTS billing_type  VARCHAR(40),
    ADD COLUMN IF NOT EXISTS gst_number    VARCHAR(50),
    ADD COLUMN IF NOT EXISTS taluk         VARCHAR(120),
    ADD COLUMN IF NOT EXISTS area          VARCHAR(160),
    ADD COLUMN IF NOT EXISTS street        VARCHAR(200);

UPDATE users SET email_verified = TRUE WHERE email LIKE '%@%' AND email_verified IS NOT TRUE;

COMMIT;


-- #############################################################################
-- 07_owner_profile_extended.sql
-- #############################################################################
BEGIN;

ALTER TABLE users
    ADD COLUMN IF NOT EXISTS username          VARCHAR(100),
    ADD COLUMN IF NOT EXISTS pin               VARCHAR(10),
    ADD COLUMN IF NOT EXISTS shop_control      VARCHAR(40),
    ADD COLUMN IF NOT EXISTS secondary_mobile  VARCHAR(50),
    ADD COLUMN IF NOT EXISTS addr_state        VARCHAR(120),
    ADD COLUMN IF NOT EXISTS addr_district     VARCHAR(120),
    ADD COLUMN IF NOT EXISTS addr_taluk        VARCHAR(120),
    ADD COLUMN IF NOT EXISTS addr_area         VARCHAR(160),
    ADD COLUMN IF NOT EXISTS addr_street       VARCHAR(200),
    ADD COLUMN IF NOT EXISTS addr_pincode      VARCHAR(20);

CREATE UNIQUE INDEX IF NOT EXISTS uq_users_shop_username
    ON users(shop_id, username) WHERE username IS NOT NULL;

UPDATE users SET username = email WHERE username IS NULL AND email IS NOT NULL;

COMMIT;


-- #############################################################################
-- 08_drop_unused_profile_fields.sql
-- #############################################################################
BEGIN;

DROP INDEX IF EXISTS uq_users_shop_username;

ALTER TABLE users
    DROP COLUMN IF EXISTS username,
    DROP COLUMN IF EXISTS pin;

ALTER TABLE shops
    DROP COLUMN IF EXISTS shop_type,
    DROP COLUMN IF EXISTS business_type,
    DROP COLUMN IF EXISTS billing_type,
    DROP COLUMN IF EXISTS city;

COMMIT;


-- #############################################################################
-- 09_drop_shop_control.sql
-- #############################################################################
BEGIN;

ALTER TABLE users DROP COLUMN IF EXISTS shop_control;

COMMIT;


-- #############################################################################
-- 10_users_shop_nullable.sql
-- #############################################################################
BEGIN;

ALTER TABLE users ALTER COLUMN shop_id DROP NOT NULL;

UPDATE users SET shop_id = NULL
  WHERE shop_id IN (SELECT id FROM shops WHERE slug = 'admin');

DELETE FROM shops WHERE slug = 'admin';

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint WHERE conname = 'uq_users_email'
    ) THEN
        ALTER TABLE users ADD CONSTRAINT uq_users_email UNIQUE (email);
    END IF;
END $$;

COMMIT;


