-- #############################################################################
-- 13_marketplace_listings.sql
-- #############################################################################
BEGIN;

CREATE TABLE IF NOT EXISTS marketplace_listings (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    seller_type     VARCHAR(20) NOT NULL,
    seller_id       UUID NOT NULL,
    shop_id         UUID,
    category_id     UUID,
    brand_id        UUID,
    model_id        UUID,
    product_name    VARCHAR(255) NOT NULL,
    product_image   VARCHAR(1000),
    "condition"     VARCHAR(40),
    description     TEXT,
    expected_price  DECIMAL(12, 2) NOT NULL,
    latitude        NUMERIC(10, 7),
    longitude       NUMERIC(10, 7),
    address         TEXT,
    city            VARCHAR(120),
    state           VARCHAR(120),
    pincode         VARCHAR(20),
    status          VARCHAR(20) NOT NULL DEFAULT 'AVAILABLE',
    created_at      TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at      TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_marketplace_listings_status   ON marketplace_listings(status);
CREATE INDEX IF NOT EXISTS idx_marketplace_listings_seller   ON marketplace_listings(seller_type, seller_id);
CREATE INDEX IF NOT EXISTS idx_marketplace_listings_geo      ON marketplace_listings(latitude, longitude);
CREATE INDEX IF NOT EXISTS idx_marketplace_listings_created  ON marketplace_listings(created_at DESC);

COMMIT;


-- #############################################################################
-- 14_shop_pickup_options.sql
-- #############################################################################
BEGIN;

ALTER TABLE shops
    ADD COLUMN IF NOT EXISTS pickup_from_time    VARCHAR(16),
    ADD COLUMN IF NOT EXISTS pickup_to_time      VARCHAR(16),
    ADD COLUMN IF NOT EXISTS pickup_distance_km  INTEGER,
    ADD COLUMN IF NOT EXISTS pickup_enabled      BOOLEAN NOT NULL DEFAULT FALSE;

CREATE INDEX IF NOT EXISTS idx_shops_pickup_enabled ON shops(pickup_enabled) WHERE pickup_enabled = TRUE;

COMMIT;


