    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint WHERE conname = 'uq_series_cb_slug'
    ) THEN
        ALTER TABLE master_device_series
            ADD CONSTRAINT uq_series_cb_slug UNIQUE (category_brand_id, slug);
    END IF;
